/**
 * 读取配置文件
 * @returns
 */
const parseDataFile = async (name) => {
    const path = joinPath(global.lxOldDataPath, name);
    if (await checkPath(path)) {
        try {
            return JSON.parse((await external_node_fs_default().promises.readFile(path)).toString());
        }
        catch (err) {
            node_default().error(err);
        }
    }
    return null;
};
/**
 * 迁移 v2.0.0 之前的 list data
 * @returns
 */
const migrateDBData = async () => {
    let playList = await parseDataFile('playList.json');
    let listDataAll = {
        defaultList: [],
        loveList: [],
        userList: [],
        tempList: [],
    };
    let isRequiredSave = false;
    if (playList) {
        if (playList.defaultList)
            listDataAll.defaultList = filterMusicList(playList.defaultList.list.map(m => toNewMusicInfo(m)));
        if (playList.loveList)
            listDataAll.loveList = filterMusicList(playList.loveList.list.map(m => toNewMusicInfo(m)));
        if (playList.tempList)
            listDataAll.tempList = filterMusicList(playList.tempList.list.map(m => toNewMusicInfo(m)));
        if (playList.userList) {
            listDataAll.userList = playList.userList.map(l => {
                return {
                    ...l,
                    locationUpdateTime: l.locationUpdateTime ?? null,
                    list: filterMusicList(l.list.map(m => toNewMusicInfo(m))),
                };
            });
        }
        isRequiredSave = true;
    }
    else {
        const config = await parseDataFile('config.json');
        if (config?.list) {
            const list = config.list;
            if (list.defaultList)
                listDataAll.defaultList = filterMusicList(list.defaultList.map(m => toNewMusicInfo(m)));
            if (list.loveList)
                listDataAll.loveList = filterMusicList(list.loveList.map(m => toNewMusicInfo(m)));
            isRequiredSave = true;
        }
    }
    if (isRequiredSave)
        await global.lx.worker.dbService.listDataOverwrite(listDataAll);
    const lyricData = await parseDataFile('lyrics_edited.json');
    if (lyricData) {
        for await (const [id, info] of Object.entries(lyricData)) {
            await global.lx.worker.dbService.editedLyricAdd(id, info);
        }
    }
};
// 迁移文件
const migrateFile = async (name, targetName) => {
    let path = joinPath(global.lxDataPath, targetName);
    let oldPath = joinPath(global.lxOldDataPath, name);
    if (!await checkPath(path) && await checkPath(oldPath)) {
        await external_node_fs_default().promises.copyFile(oldPath, path).catch(err => {
            node_default().error(err);
        }).catch(err => {
            node_default().error(err);
        });
    }
};
/**
 * 迁移 v2.0.0 之前的 data.json
 * @returns
 */
const migrateDataJson = async () => {
    const path = joinPath(global.lxDataPath, 'data.json');
    if (await checkPath(path))
        return;
    const oldDataFile = await parseDataFile('data.json');
    if (!oldDataFile)
        return;
    const newData = {};
    if (oldDataFile.searchHistoryList)
        newData.searchHistoryList = oldDataFile.searchHistoryList;
    if (oldDataFile.playInfo)
        newData.playInfo = oldDataFile.playInfo;
    if (oldDataFile.listPrevSelectId)
        newData.listPrevSelectId = oldDataFile.listPrevSelectId;
    if (oldDataFile.listPosition)
        newData.listScrollPosition = oldDataFile.listPosition;
    if (oldDataFile.listUpdateInfo)
        newData.listUpdateInfo = oldDataFile.listUpdateInfo;
    await external_node_fs_default().promises.writeFile(path, JSON.stringify(newData)).catch(err => {
        node_default().error(err);
    });
};
const hotKeyNameMap = {
    mainWindow: APP_EVENT_NAMES.winMainName,
    winLyric: APP_EVENT_NAMES.winLyricName,
};
const updateHotKeyTypeName = (config) => {
    for (const keyConfig of Object.values(config.keys)) {
        if (hotKeyNameMap[keyConfig.type])
            keyConfig.type = hotKeyNameMap[keyConfig.type];
    }
};
/**
 * 迁移 v2.0.0 之前的 hotkey
 * @returns
 */
const migrateHotKey = async () => {
    const oldConfig = await parseDataFile('hotKey.json');
    if (oldConfig) {
        let localConfig;
        let globalConfig;
        updateHotKeyTypeName(oldConfig.local);
        updateHotKeyTypeName(oldConfig.global);
        localConfig = oldConfig.local;
        globalConfig = oldConfig.global;
        // 移除v1.0.1及之前设置的全局声音媒体快捷键接管
        if (globalConfig.keys.VolumeUp) {
            delete globalConfig.keys.VolumeUp;
            delete globalConfig.keys.VolumeDown;
            delete globalConfig.keys.VolumeMute;
        }
        return {
            local: localConfig,
            global: globalConfig,
        };
    }
    return null;
};
/**
 * 迁移 v2.0.0 之前的user api
 * @returns
 */
const migrateUserApi = async () => migrateFile('userApi.json', STORE_NAMES.USER_API + '.json');

