const parseEnvParams = (argv = process.argv) => {
    const cmdParams = {};
    let deeplink = null;
    const rx = /^-\w+/;
    for (let param of argv) {
        if (URL_SCHEME_RXP.test(param)) {
            deeplink = param;
        }
        if (!rx.test(param))
            continue;
        param = param.substring(1);
        let index = param.indexOf('=');
        if (index < 0) {
            cmdParams[param] = true;
        }
        else {
            cmdParams[param.substring(0, index)] = param.substring(index + 1);
        }
    }
    return {
        cmdParams,
        deeplink,
    };
};
const primitiveType = ['string', 'boolean', 'number'];
const checkPrimitiveType = (val) => val === null || primitiveType.includes(typeof val);
