let userThemes;
const getAllThemes = () => {
    userThemes ??= store(STORE_NAMES.THEME).get('themes') ?? [];
    return {
        themes: theme_namespaceObject,
        userThemes,
        dataPath: joinPath(global.lxDataPath, 'theme_images'),
    };
};
const saveTheme = (theme) => {
    const targetTheme = userThemes.find(t => t.id === theme.id);
    if (targetTheme)
        Object.assign(targetTheme, theme);
    else
        userThemes.push(theme);
    store(STORE_NAMES.THEME).set('themes', userThemes);
};
const removeTheme = (id) => {
    const index = userThemes.findIndex(t => t.id === id);
    if (index < 0)
        return;
    userThemes.splice(index, 1);
    store(STORE_NAMES.THEME).set('themes', userThemes);
};
const copyTheme = (theme) => {
    return {
        ...theme,
        config: {
            ...theme.config,
            extInfo: { ...theme.config.extInfo },
            themeColors: { ...theme.config.themeColors },
        },
    };
};
const getTheme = () => {
    // fs.promises.readdir()
    const shouldUseDarkColors = external_electron_namespaceObject.nativeTheme.shouldUseDarkColors;
    let themeId = global.lx.appSetting['theme.id'] == 'auto'
        ? shouldUseDarkColors
            ? global.lx.appSetting['theme.darkId']
            : global.lx.appSetting['theme.lightId']
        : global.lx.appSetting['theme.id'];
    // themeId = 'naruto'
    // themeId = 'pink'
    // themeId = 'black'
    let theme = theme_namespaceObject.find(theme => theme.id == themeId);
    if (!theme) {
        userThemes = store(STORE_NAMES.THEME).get('themes') ?? [];
        theme = userThemes.find(theme => theme.id == themeId);
        if (theme) {
            if (theme.config.extInfo['--background-image'] != 'none') {
                theme = copyTheme(theme);
                theme.config.extInfo['--background-image'] =
                    isUrl(theme.config.extInfo['--background-image'])
                        ? `url(${theme.config.extInfo['--background-image']})`
                        : `url(file:///${encodePath(joinPath(global.lxDataPath, 'theme_images', theme.config.extInfo['--background-image']))})`;
            }
        }
        else {
            themeId = global.lx.appSetting['theme.id'] == 'auto' && shouldUseDarkColors ? 'black' : 'green';
            theme = theme_namespaceObject.find(theme => theme.id == themeId);
        }
    }
    const colors = {
        ...theme.config.themeColors,
        ...theme.config.extInfo,
    };
    return {
        shouldUseDarkColors,
        theme: {
            id: global.lx.appSetting['theme.id'],
            name: theme.name,
            isDark: theme.isDark,
            isDarkFont: theme.isDarkFont,
            colors,
        },
    };
};
let powerSaveBlockerId = null;
const setPowerSaveBlocker = (enabled) => {
    let isEnabled = powerSaveBlockerId != null && external_electron_namespaceObject.powerSaveBlocker.isStarted(powerSaveBlockerId);
    if (enabled) {
        if (isEnabled)
            return;
        powerSaveBlockerId = external_electron_namespaceObject.powerSaveBlocker.start(isMac ? 'prevent-display-sleep' : 'prevent-app-suspension');
    }
    else {
        if (!isEnabled)
            return;
        external_electron_namespaceObject.powerSaveBlocker.stop(powerSaveBlockerId);
        powerSaveBlockerId = null;
    }
};
let envProxy = null;
const getProxy = () => {
    if (global.lx.appSetting['network.proxy.enable'] && global.lx.appSetting['network.proxy.host']) {
        return {
            host: global.lx.appSetting['network.proxy.host'],
            port: parseInt(global.lx.appSetting['network.proxy.port'] || '80'),
        };
    }
    if (envProxy) {
        return {
            host: envProxy.host,
            port: envProxy.port,
        };
    }
    else {
        const envProxyStr = envParams.cmdParams['proxy-server'];
        if (envProxyStr && typeof envProxyStr == 'string') {
            const [host, port = ''] = envProxyStr.split(':');
            return envProxy = {
                host,
                port: parseInt(port || '80'),
            };
        }
    }
    return null;
};

