/* unused harmony import specifier */ var shell;
/* unused harmony import specifier */ var clipboard;

/**
 * 在资源管理器中打开目录
 * @param {string} dir
 */
const openDirInExplorer = (dir) => {
    external_electron_namespaceObject.shell.showItemInFolder(dir);
};
/**
 * 在浏览器打开URL
 * @param {*} url
 */
const openUrl = async (url) => {
    if (!/^https?:\/\//.test(url))
        return;
    await shell.openExternal(url);
};
/**
 * 复制文本到剪贴板
 * @param str
 */
const clipboardWriteText = (str) => {
    clipboard.writeText(str);
};
/**
 * 从剪贴板读取文本
 * @returns
 */
const clipboardReadText = () => {
    return clipboard.readText();
};
const electron_encodePath = (path) => {
    // https://github.com/lyswhut/lx-music-desktop/issues/963
    // https://github.com/lyswhut/lx-music-desktop/issues/1461
    return path.replaceAll('%', '%25').replaceAll('#', '%23');
};

