const hello = async (urlInfo) => utils_request(`${urlInfo.httpProtocol}//${urlInfo.hostPath}/hello`)
    .then(({ text }) => text == SYNC_CODE.helloMsg)
    .catch((err) => {
    sync_log.error('[auth] hello', err.message);
    console.log(err);
    return false;
});
const getServerId = async (urlInfo) => utils_request(`${urlInfo.httpProtocol}//${urlInfo.hostPath}/id`)
    .then(({ text }) => {
    if (!text.startsWith(SYNC_CODE.idPrefix))
        return '';
    return text.replace(SYNC_CODE.idPrefix, '');
})
    .catch((err) => {
    sync_log.error('[auth] getServerId', err.message);
    console.log(err);
    throw err;
});
const codeAuth = async (urlInfo, serverId, authCode) => {
    let key = toMD5(authCode).substring(0, 16);
    // const iv = Buffer.from(key.split('').reverse().join('')).toString('base64')
    key = Buffer.from(key).toString('base64');
    let { publicKey, privateKey } = await generateRsaKey();
    publicKey = publicKey.replace(/\n/g, '')
        .replace('-----BEGIN PUBLIC KEY-----', '')
        .replace('-----END PUBLIC KEY-----', '');
    const msg = aesEncrypt(`${SYNC_CODE.authMsg}\n${publicKey}\n${getComputerName()}\nlx_music_desktop`, key);
    // console.log(msg, key)
    return utils_request(`${urlInfo.httpProtocol}//${urlInfo.hostPath}/ah`, { headers: { m: msg } }).then(async ({ text, code }) => {
        // console.log(text)
        switch (text) {
            case SYNC_CODE.msgBlockedIp:
                throw new Error(SYNC_CODE.msgBlockedIp);
            case SYNC_CODE.authFailed:
                throw new Error(SYNC_CODE.authFailed);
            default:
                if (code != 200)
                    throw new Error(SYNC_CODE.authFailed);
        }
        let msg;
        try {
            msg = rsaDecrypt(Buffer.from(text, 'base64'), privateKey).toString();
        }
        catch (err) {
            sync_log.error('[auth] codeAuth decryptMsg error', err.message);
            throw new Error(SYNC_CODE.authFailed);
        }
        // console.log(msg)
        if (!msg)
            return Promise.reject(new Error(SYNC_CODE.authFailed));
        const info = JSON.parse(msg);
        void setSyncAuthKey(serverId, info);
        return info;
    });
};
const keyAuth = async (urlInfo, keyInfo) => {
    const msg = aesEncrypt(SYNC_CODE.authMsg + getComputerName(), keyInfo.key);
    // eslint-disable-next-line @typescript-eslint/promise-function-async
    return utils_request(`${urlInfo.httpProtocol}//${urlInfo.hostPath}/ah`, { headers: { i: keyInfo.clientId, m: msg } }).then(({ text, code }) => {
        if (code != 200)
            throw new Error(SYNC_CODE.authFailed);
        let msg;
        try {
            msg = aesDecrypt(text, keyInfo.key);
        }
        catch (err) {
            sync_log.error('[auth] keyAuth decryptMsg error', err.message);
            throw new Error(SYNC_CODE.authFailed);
        }
        if (msg != SYNC_CODE.helloMsg)
            return Promise.reject(new Error(SYNC_CODE.authFailed));
    });
};
const auth = async (urlInfo, serverId, authCode) => {
    if (authCode)
        return codeAuth(urlInfo, serverId, authCode);
    const keyInfo = await getSyncAuthKey(serverId);
    if (!keyInfo)
        throw new Error(SYNC_CODE.missingAuthCode);
    await keyAuth(urlInfo, keyInfo);
    return keyInfo;
};
/* harmony default export */ const client_auth = (async (urlInfo, authCode) => {
    console.log('connect: ', urlInfo.href, authCode);
    if (!await hello(urlInfo))
        throw new Error(SYNC_CODE.connectServiceFailed);
    const serverId = await getServerId(urlInfo);
    if (!serverId)
        throw new Error(SYNC_CODE.getServiceIdFailed);
    return auth(urlInfo, serverId, authCode);
});
(Object.getOwnPropertyDescriptor(client_auth, "name") || {}).writable || Object.defineProperty(client_auth, "name", { value: "default", configurable: true });

