const createClientKeyInfo = (deviceName, isMobile) => {
    const keyInfo = {
        clientId: (0,external_node_crypto_.randomBytes)(4 * 4).toString('base64'),
        key: (0,external_node_crypto_.randomBytes)(16).toString('base64'),
        deviceName,
        isMobile,
        lastConnectDate: 0,
    };
    return keyInfo;
};
class UserDataManage {
    userName;
    userDir;
    devicesFilePath;
    devicesInfo;
    saveDevicesInfoThrottle;
    getAllClientKeyInfo = () => {
        return Object.values(this.devicesInfo.clients).sort((a, b) => (b.lastConnectDate ?? 0) - (a.lastConnectDate ?? 0));
    };
    saveClientKeyInfo = (keyInfo) => {
        if (this.devicesInfo.clients[keyInfo.clientId] == null && Object.keys(this.devicesInfo.clients).length > 101)
            throw new Error('max keys');
        this.devicesInfo.clients[keyInfo.clientId] = keyInfo;
        this.saveDevicesInfoThrottle();
    };
    getClientKeyInfo = (clientId) => {
        if (!clientId)
            return null;
        return this.devicesInfo.clients[clientId] ?? null;
    };
    removeClientKeyInfo = async (clientId) => {
        // eslint-disable-next-line @typescript-eslint/no-dynamic-delete
        delete this.devicesInfo.clients[clientId];
        this.saveDevicesInfoThrottle();
    };
    isIncluedsClient = (clientId) => {
        return Object.values(this.devicesInfo.clients).some(client => client.clientId == clientId);
    };
    constructor(userName) {
        this.userName = userName;
        const syncDataPath = external_node_path_default().join(global.lxDataPath, File.serverDataPath);
        this.userDir = syncDataPath;
        this.devicesFilePath = external_node_path_default().join(this.userDir, File.userDevicesJSON);
        this.devicesInfo = external_node_fs_default().existsSync(this.devicesFilePath) ? JSON.parse(external_node_fs_default().readFileSync(this.devicesFilePath).toString()) : { userName, clients: {} };
        this.saveDevicesInfoThrottle = throttle(() => {
            external_node_fs_default().writeFile(this.devicesFilePath, JSON.stringify(this.devicesInfo), 'utf8', (err) => {
                if (err)
                    console.error(err);
            });
        });
    }
}
