;// ./src/main/modules/sync/server/server/sync/sync.ts


const sync_sync_sync = async (socket) => {
    let disconnected = false;
    socket.onClose(() => {
        disconnected = true;
    });
    const enabledFeatures = await socket.remote.getEnabledFeatures('desktop-app', modules_featureVersion);
    if (disconnected)
        throw new Error('disconnected');
    for (const moduleName of FeaturesList) {
        if (enabledFeatures[moduleName]) {
            socket.feature[moduleName] = enabledFeatures[moduleName];
            await server_modules_modules[moduleName].sync(socket).catch(_ => _);
        }
        if (disconnected)
            throw new Error('disconnected');
    }
    await socket.remote.finished();
};

