const removeDevice = async (clientId) => {
    if (wss) {
        for (const client of wss.clients) {
            if (client.keyInfo.clientId == clientId)
                client.close(SYNC_CLOSE_CODE.normal);
        }
    }
    const userSpace = getUserSpace();
    await userSpace.removeDevice(clientId);
};

